  const { data } = await sb.from\('course_lessons'\).select\('id, title, content_markdown, content_html, content_blocks'\).in\('topic_id', ids\).limit\(2\);
  data?.forEach\(l => {
    console.log\('ID:', l.id, 'Title:', l.title?.slice\(0,40\)\);
    console.log\('  markdown:', l.content_markdown?.slice\(0,60\) || 'NULL'\);
    console.log\('  html:', !!l.content_html, '  blocks:', !!l.content_blocks\);
  }\);
}
run\(\).catch\(console.error\);
